def tla_checkpoint() -> str:
    return textwrap.dedent(
        f"""\
        ---- MODULE Z00Z_Checkpoint ----
        \\* {GEN_MARKER}
        EXTENDS FiniteSets, Naturals, TLC

        Inputs == 1..3
        Outputs == 11..13

        VARIABLES
          \\* @type: Set(Int);
          liveInputs,
          \\* @type: Set(Int);
          spentDelta,
          \\* @type: Set(Int);
          createdDelta,
          \\* @type: Bool;
          finalized

        TypeOK ==
          /\\ liveInputs \\subseteq Inputs
          /\\ spentDelta \\subseteq Inputs
          /\\ createdDelta \\subseteq Outputs
          /\\ finalized \\in BOOLEAN

        Init ==
          /\\ liveInputs = Inputs
          /\\ spentDelta = {{}}
          /\\ createdDelta = {{}}
          /\\ finalized = FALSE

        Propose ==
          \\E spend \\in SUBSET liveInputs:
            \\E create \\in SUBSET Outputs:
              /\\ spend # {{}}
              /\\ create # {{}}
              /\\ Cardinality(create) = Cardinality(spend)
              /\\ ~finalized
              /\\ spend \\cap spentDelta = {{}}
              /\\ create \\cap createdDelta = {{}}
              /\\ liveInputs' = liveInputs \\ spend
              /\\ spentDelta' = spentDelta \\cup spend
              /\\ createdDelta' = createdDelta \\cup create
              /\\ UNCHANGED finalized

        Finalize ==
          /\\ ~finalized
          /\\ Cardinality(spentDelta) = Cardinality(createdDelta)
          /\\ finalized' = TRUE
          /\\ UNCHANGED <<liveInputs, spentDelta, createdDelta>>

        Hold ==
          /\\ finalized
          /\\ UNCHANGED <<liveInputs, spentDelta, createdDelta, finalized>>

        \\* @type: () => <<Set(Int), Set(Int), Set(Int), Bool>>;
        CheckpointVars == <<liveInputs, spentDelta, createdDelta, finalized>>

        Next == Propose \\/ Finalize \\/ Hold

        NoDoubleSpend == spentDelta \\subseteq Inputs
        FinalizedSupplyBalanced ==
          finalized => Cardinality(spentDelta) = Cardinality(createdDelta)

        Spec == Init /\\ [][Next]_CheckpointVars
        ====
        """
    )


