def tla_aggregator() -> str:
    return textwrap.dedent(
        f"""\
        ---- MODULE Z00Z_Aggregator ----
        \\* {GEN_MARKER}
        EXTENDS FiniteSets, Naturals

        BatchIds == 1..3

        VARIABLES
          \\* @type: Set(Int);
          pending,
          \\* @type: Set(Int);
          committed,
          \\* @type: Set(Int);
          published

        TypeOK ==
          /\\ pending \\subseteq BatchIds
          /\\ committed \\subseteq BatchIds
          /\\ published \\subseteq BatchIds

        Init ==
          /\\ pending = {{}}
          /\\ committed = {{}}
          /\\ published = {{}}

        Queue ==
          \\E b \\in BatchIds \\ (pending \\cup committed \\cup published):
            /\\ pending' = pending \\cup {{b}}
            /\\ UNCHANGED <<committed, published>>

        Commit ==
          \\E b \\in pending:
            /\\ pending' = pending \\ {{b}}
            /\\ committed' = committed \\cup {{b}}
            /\\ UNCHANGED published

        Publish ==
          \\E b \\in committed \\ published:
            /\\ published' = published \\cup {{b}}
            /\\ UNCHANGED <<pending, committed>>

        Done ==
          /\\ pending = {{}}
          /\\ published = committed
          /\\ UNCHANGED <<pending, committed, published>>

        \\* @type: () => <<Set(Int), Set(Int), Set(Int)>>;
        AggVars == <<pending, committed, published>>

        Next == Queue \\/ Commit \\/ Publish \\/ Done

        PublishRequiresCommit == published \\subseteq committed
        NoDuplicateLifecycle ==
          /\\ pending \\cap committed = {{}}
          /\\ pending \\cap published = {{}}

        Spec == Init /\\ [][Next]_AggVars
        ====
        """
    )


