def alloy_asset_model() -> str:
    return textwrap.dedent(
        f"""\
        // {GEN_MARKER}
        abstract sig TransferMode {{}}
        one sig Transferable, NonTransferable extends TransferMode {{}}

        abstract sig VoucherState {{}}
        one sig Fresh, Redeemed extends VoucherState {{}}

        sig Asset {{}}
        sig Policy {{}}

        sig Right {{
          asset: one Asset,
          policy: one Policy,
          mode: one TransferMode
        }}

        sig Voucher {{
          asset: one Asset,
          consumes: lone Right,
          state: one VoucherState
        }}

        sig Wrapper {{
          wraps: one Right,
          redeems: lone Voucher
        }}

        pred WellFormed {{
          all v: Voucher | some v.consumes implies v.consumes.asset = v.asset
          all w: Wrapper | some w.redeems implies w.redeems.asset = w.wraps.asset
        }}

        fun redeemedBy[v: Voucher]: set Wrapper {{
          redeems.v
        }}

        fact RedemptionDiscipline {{
          all v: Voucher | v.state = Redeemed iff one redeemedBy[v]
          all w: Wrapper | some w.redeems implies {{
            w.wraps.mode = Transferable
            w.redeems.state = Redeemed
            w.redeems.consumes = w.wraps
          }}
        }}

        assert NoVoucherDoubleRedeem {{
          WellFormed implies all disj w1, w2: Wrapper |
            some w1.redeems and w1.redeems = w2.redeems implies w1 = w2
        }}

        assert NonTransferableCannotMoveViaWrapper {{
          WellFormed implies all w: Wrapper |
            w.wraps.mode = NonTransferable implies no w.redeems
        }}

        assert VoucherCannotLoseAssetLineage {{
          WellFormed implies all v: Voucher | some v.consumes implies v.asset = v.consumes.asset
        }}

        check NoVoucherDoubleRedeem for 6
        check NonTransferableCannotMoveViaWrapper for 6
        check VoucherCannotLoseAssetLineage for 6
        """
    )


