def tamarin_payment_request() -> str:
    return textwrap.dedent(
        f"""\
        theory z00z_payment_request begin

        /* {GEN_MARKER} */
        builtins: hashing

        functions: req/2

        rule Issue:
          [ Fr(~rid), Fr(~ctx) ]
          -->
          [ Request(~rid, ~ctx), Out(req(~rid, ~ctx)) ]

        rule Accept:
          [ Request(rid, ctx), In(req(rid, ctx)) ]
          -->
          [ Accepted(rid, ctx) ]

        lemma accept_implies_issue:
          "All rid ctx #i. Accepted(rid, ctx) @ i ==> Ex #j. Request(rid, ctx) @ j & #j < #i"

        lemma no_cross_context_replay:
          "All rid ctx1 ctx2 #i #j.
             Accepted(rid, ctx1) @ i
             & Accepted(rid, ctx2) @ j
             ==> ctx1 = ctx2"

        end
        """
    )


def tamarin_stealth_delivery() -> str:
    return textwrap.dedent(
        f"""\
        theory z00z_stealth_delivery begin

        /* {GEN_MARKER} */
        builtins: hashing

        functions: notice/3, owner_tag/2

        rule Send:
          [ Fr(~ephem), Fr(~payload) ]
          --[ Sent($receiver, ~payload, ~ephem) ]->
          [ !PendingDelivery($receiver, ~payload, ~ephem),
            Out(<owner_tag(~ephem, $receiver), notice(~payload, $receiver, ~ephem)>) ]

        rule Receive:
          [ !PendingDelivery($receiver, payload, ephem),
            In(<owner_tag(ephem, $receiver), notice(payload, $receiver, ephem)>) ]
          --[ Received($receiver, payload, ephem) ]->
          [ ]

        lemma receive_implies_send:
          "All receiver payload ephem #i.
             Received(receiver, payload, ephem) @ i
             ==> Ex #j. Sent(receiver, payload, ephem) @ j & #j < #i"

        end
        """
    )


def tamarin_inbox_notify() -> str:
    return textwrap.dedent(
        f"""\
        theory z00z_inbox_notify begin

        /* {GEN_MARKER} */
        builtins: hashing

        functions: notify/2

        rule Publish:
          [ Fr(~msg), Fr(~ctx) ]
          --[ Notice(~msg, ~ctx) ]->
          [ !Published(~msg, ~ctx), Out(notify(~msg, ~ctx)) ]

        rule Observe:
          [ !Published(msg, ctx), In(notify(msg, ctx)) ]
          --[ Observed(msg, ctx) ]->
          [ ]

        lemma observe_implies_publish:
          "All msg ctx #i. Observed(msg, ctx) @ i ==> Ex #j. Notice(msg, ctx) @ j & #j < #i"

        end
        """
    )


def proverif_payment_request() -> str:
    return textwrap.dedent(
        f"""\
        (* {GEN_MARKER} *)
        free c: channel.
        fun req(bitstring, bitstring): bitstring.

        event Issue(bitstring, bitstring).
        event Accept(bitstring, bitstring).

        query rid: bitstring, ctx: bitstring; event(Accept(rid, ctx)) ==> event(Issue(rid, ctx)).

        process
          new rid: bitstring;
          new ctx: bitstring;
          let r = req(rid, ctx) in
          event Issue(rid, ctx);
          out(c, r);
          in(c, x: bitstring);
          if x = r then event Accept(rid, ctx)
        """
    )


def proverif_stealth_delivery() -> str:
    return textwrap.dedent(
        f"""\
        (* {GEN_MARKER} *)
        free c: channel.
        fun notify(bitstring, bitstring): bitstring.

        event Sent(bitstring, bitstring).
        event Received(bitstring, bitstring).

        query payload: bitstring, receiver: bitstring;
          event(Received(payload, receiver)) ==> event(Sent(payload, receiver)).

        process
          new payload: bitstring;
          new receiver: bitstring;
          let msg = notify(payload, receiver) in
          event Sent(payload, receiver);
          out(c, msg);
          in(c, x: bitstring);
          if x = msg then event Received(payload, receiver)
        """
    )


def tamarin_voucher_acceptance() -> str:
    return textwrap.dedent(
        f"""\
        theory z00z_voucher_acceptance begin

        /* {GEN_MARKER} */
        builtins: hashing

        functions: voucher/2

        rule Issue:
          [ Fr(~vid), Fr(~asset) ]
          --[ Issued(~vid, ~asset) ]->
          [ Pending(~vid, ~asset), Out(voucher(~vid, ~asset)) ]

        rule Accept:
          [ Pending(vid, asset), In(voucher(vid, asset)) ]
          --[ Accepted(vid, asset) ]->
          [ AcceptedFact(vid, asset) ]

        rule Redeem:
          [ AcceptedFact(vid, asset) ]
          --[ Redeemed(vid, asset) ]->
          [ ]

        rule Refuse:
          [ Pending(vid, asset), In(voucher(vid, asset)) ]
          --[ Refused(vid, asset) ]->
          [ ]

        lemma redeem_implies_accept:
          "All vid asset #i. Redeemed(vid, asset) @ i ==> Ex #j. Accepted(vid, asset) @ j & #j < #i"

        lemma accept_implies_issue:
          "All vid asset #i. Accepted(vid, asset) @ i ==> Ex #j. Issued(vid, asset) @ j & #j < #i"

        lemma refusal_and_accept_cannot_both_happen:
          "All vid asset #i #j. Refused(vid, asset) @ i & Accepted(vid, asset) @ j ==> F"

        end
        """
    )


def proverif_voucher_acceptance() -> str:
    return textwrap.dedent(
        f"""\
        (* {GEN_MARKER} *)
        free c: channel.
        fun voucher(bitstring, bitstring): bitstring.

        event Issue(bitstring, bitstring).
        event Accept(bitstring, bitstring).
        event Redeem(bitstring, bitstring).

        query vid: bitstring, asset: bitstring; event(Accept(vid, asset)) ==> event(Issue(vid, asset)).
        query vid: bitstring, asset: bitstring; event(Redeem(vid, asset)) ==> event(Accept(vid, asset)).

        process
          new vid: bitstring;
          new asset: bitstring;
          let v = voucher(vid, asset) in
          event Issue(vid, asset);
          out(c, v);
          in(c, x: bitstring);
          if x = v then
            event Accept(vid, asset);
            event Redeem(vid, asset)
        """
    )


