def code_to_logic_zkpack_lib(root: Path, verification_root_rel: str) -> str:
    crate_src_dir = root / code_to_logic_generated_root(verification_root_rel) / "zkpack_verify/src"
    zkpack_src = root / "crates/z00z_crypto/src/protocol/zkpack.rs"
    zkpack_rel = rel_between(crate_src_dir, zkpack_src)
    ciphertext_syms = symbolic_u8_array("ct", 72)
    tag_syms = symbolic_u8_array("tag", 16)
    return textwrap.dedent(
        f"""\
        #![allow(unexpected_cfgs)]

        #[path = "{zkpack_rel}"]
        pub mod zkpack;

        pub fn zkpack_roundtrip(
            ciphertext: [u8; zkpack::ZKPACK_CT_LEN],
            tag: [u8; zkpack::ZKPACK_TAG_LEN],
        ) -> bool {{
            let original = zkpack::ZkPackEncrypted {{
                version: zkpack::ZKPACK_VER,
                ciphertext: ciphertext.to_vec(),
                tag,
            }};
            match original.to_bytes() {{
                Ok(bytes) => match zkpack::ZkPackEncrypted::from_bytes(&bytes) {{
                    Ok(decoded) => decoded == original,
                    Err(_) => false,
                }},
                Err(_) => false,
            }}
        }}

        pub fn zkpack_rejects_bad_version(version: u8) -> bool {{
            let mut bytes = [0u8; zkpack::ZKPACK_TOTAL_LEN];
            bytes[0] = version;
            match zkpack::ZkPackEncrypted::from_bytes(&bytes) {{
                Ok(decoded) => version == zkpack::ZKPACK_VER && decoded.version == zkpack::ZKPACK_VER,
                Err(zkpack::ZkPackWireError::UnsupportedVersion) => version != zkpack::ZKPACK_VER,
                Err(_) => false,
            }}
        }}

        #[cfg(crux)]
        #[allow(dead_code)]
        mod crux_test {{
            extern crate crucible;

            use super::*;
            use crucible::*;

            #[crux::test]
            fn zkpack_roundtrip_holds() {{
                let ciphertext = [
        {ciphertext_syms}
                ];
                let tag = [
        {tag_syms}
                ];
                crucible_assert!(zkpack_roundtrip(ciphertext, tag));
            }}

            #[crux::test]
            fn zkpack_rejects_bad_version_holds() {{
                let version = u8::symbolic("version");
                crucible_assert!(zkpack_rejects_bad_version(version));
            }}
        }}
        """
    )


