def verus_validator_determinism() -> str:
    return textwrap.dedent(
        """\
        use vstd::prelude::*;

        verus! {

        spec fn validator_accept(
            root_ok: bool,
            binding_ok: bool,
            replay_free: bool,
            proof_family_ok: bool,
        ) -> bool {
            root_ok && binding_ok && replay_free && proof_family_ok
        }

        proof fn accept_implies_all_guards(
            root_ok: bool,
            binding_ok: bool,
            replay_free: bool,
            proof_family_ok: bool,
        )
            ensures
                validator_accept(root_ok, binding_ok, replay_free, proof_family_ok)
                    ==> root_ok && binding_ok && replay_free && proof_family_ok,
        {
        }

        proof fn any_failed_guard_forces_reject(
            root_ok: bool,
            binding_ok: bool,
            replay_free: bool,
            proof_family_ok: bool,
        )
            ensures
                (!root_ok || !binding_ok || !replay_free || !proof_family_ok)
                    ==> !validator_accept(root_ok, binding_ok, replay_free, proof_family_ok),
        {
        }

        } // verus!

        fn main() {}
        """
    )


