def kani_validator_checkpoint_flow() -> str:
    return textwrap.dedent(
        """\
        #![allow(unexpected_cfgs)]
        #![cfg(kani)]

        // GENERATED BY z00z-verification-artifact-builder
        use z00z_aggregators::{
            AggregatorId, BatchId, BatchRoute, ShardExecState, ShardExecTicket, ShardId,
            ShardPlacementView,
        };

        fn placement_view(shard_id: u16, generation: u64, aggregator_id: u16) -> ShardPlacementView {
            ShardPlacementView {
                route: BatchRoute {
                    shard_id: ShardId::new(shard_id),
                    routing_generation: generation,
                },
                primary_id: AggregatorId::new(aggregator_id),
                standby: Vec::new(),
                expected_journal_lineage: [0x61; 32],
            }
        }

        fn exec_ticket(
            batch_id: BatchId,
            shard_id: u16,
            generation: u64,
            aggregator_id: u16,
            state: ShardExecState,
        ) -> ShardExecTicket {
            ShardExecTicket {
                batch_id,
                placement: placement_view(shard_id, generation, aggregator_id),
                state,
            }
        }

        fn assert_placement_matches(
            placement: &ShardPlacementView,
            shard_id: u16,
            generation: u64,
            aggregator_id: u16,
        ) {
            assert_eq!(placement.route.shard_id, ShardId::new(shard_id));
            assert_eq!(placement.route.routing_generation, generation);
            assert_eq!(placement.primary_id, AggregatorId::new(aggregator_id));
            assert!(placement.standby.is_empty());
            assert_eq!(placement.expected_journal_lineage, [0x61; 32]);
        }

        fn assert_exec_matches(
            exec_ticket: &ShardExecTicket,
            batch_id: BatchId,
            shard_id: u16,
            generation: u64,
            aggregator_id: u16,
            state: ShardExecState,
        ) {
            assert_eq!(exec_ticket.batch_id, batch_id);
            assert_eq!(exec_ticket.state, state);
            assert_placement_matches(&exec_ticket.placement, shard_id, generation, aggregator_id);
        }

        #[kani::proof]
        fn generated_validator_runtime_prefers_exec_placement() {
            let batch_id = BatchId::from_bytes([0x31; 32]);
            let fallback = placement_view(1, 7, 3);
            let exec = exec_ticket(batch_id, 1, 7, 4, ShardExecState::Running);
            let runtime_placement =
                z00z_validators::kani_runtime_placement_parts(Some(&fallback), Some(&exec))
                    .expect("runtime placement");
            assert_placement_matches(runtime_placement, 1, 7, 4);

            let runtime_exec =
                z00z_validators::kani_runtime_exec_parts(Some(&exec)).expect("runtime exec");
            assert_exec_matches(runtime_exec, batch_id, 1, 7, 4, ShardExecState::Running);
        }

        #[kani::proof]
        fn generated_validator_runtime_falls_back_to_attached_placement() {
            let fallback = placement_view(1, 7, 3);
            let runtime_placement =
                z00z_validators::kani_runtime_placement_parts(Some(&fallback), None)
                    .expect("runtime placement");
            assert_placement_matches(runtime_placement, 1, 7, 3);
            assert!(z00z_validators::kani_runtime_exec_parts(None).is_none());
        }
        """
    )


def build_artifacts(
    root: Path,
    scope_kind: str,
    target_root_rel: str,
    specs_runtime_root: str | None,
    verification_runtime_root: str | None,
    fuzz_runtime_root: str | None,
    runtime_only: bool,
) -> dict:
    summary = {"created": [], "updated": [], "skipped": []}
    metadata = cargo_metadata(root)
    _ = metadata  # workspace existence validation
    domains = scan_domain_defs(root)
    report_stamp = os.environ.get("Z00Z_REPORT_TIMESTAMP") or datetime.now(
        timezone.utc
    ).strftime("%Y%m%d-%H%M%S")
    default_run_root_rel = canonical_run_root_rel(report_stamp)
    run_root_rel = normalize_runtime_root(
        root,
        os.environ.get("Z00Z_VERIFICATION_RUN_ROOT"),
        default_run_root_rel,
    )
    ensure_canonical_run_root_rel(run_root_rel)
    specs_root_rel = normalize_runtime_root(
        root, specs_runtime_root, f"{run_root_rel}/specs{report_stamp}"
    )
    verification_root_rel = normalize_runtime_root(
        root, verification_runtime_root, f"{run_root_rel}/verification{report_stamp}"
    )
    fuzz_root_rel = normalize_runtime_root(
        root, fuzz_runtime_root, f"{run_root_rel}/fuzz{report_stamp}"
    )
    ensure_report_local_runtime_root("specs runtime root", specs_root_rel, run_root_rel)
    ensure_report_local_runtime_root(
        "verification runtime root", verification_root_rel, run_root_rel
    )
    ensure_report_local_runtime_root("fuzz runtime root", fuzz_root_rel, run_root_rel)

    want_checkpoint = scope_kind == "project" or target_root_rel.startswith(
        (
            "crates/z00z_storage",
            "crates/z00z_runtime/aggregators",
            "crates/z00z_runtime/validators",
            "crates/z00z_runtime/watchers",
        )
    )
    want_assets = scope_kind == "project" or target_root_rel.startswith(("crates/z00z_core", "crates/z00z_wallets"))
    want_crypto = scope_kind == "project" or target_root_rel.startswith(("crates/z00z_wallets", "crates/z00z_crypto", "crates/z00z_core"))
    want_exec = scope_kind == "project" or target_root_rel.startswith(
        (
            "crates/z00z_wallets",
            "crates/z00z_storage",
            "crates/z00z_core",
            "crates/z00z_crypto",
            "crates/z00z_runtime/validators",
        )
    )
    want_security_review = scope_kind == "project" or target_root_rel.startswith(
        (
            "crates/z00z_wallets",
            "crates/z00z_storage",
            "crates/z00z_core",
            "crates/z00z_crypto",
            "crates/z00z_runtime/validators",
            "crates/z00z_networks_rpc",
        )
    )

    if want_checkpoint:
        manual_or_owned_write(root, f"{specs_root_rel}/invariants/checkpoint_invariants.yaml", checkpoint_invariants(root, specs_root_rel, fuzz_root_rel), summary, "invariants")
        manual_or_owned_write(root, f"{specs_root_rel}/tla/Z00Z_Checkpoint.tla", tla_checkpoint(), summary, "tla")
        manual_or_owned_write(root, f"{specs_root_rel}/tla/Z00Z_Checkpoint.cfg", tla_checkpoint_cfg(), summary, "tla")
        manual_or_owned_write(root, f"{specs_root_rel}/tla/Z00Z_Aggregator.tla", tla_aggregator(), summary, "tla")
        manual_or_owned_write(root, f"{specs_root_rel}/tla/Z00Z_Aggregator.cfg", tla_aggregator_cfg(), summary, "tla")

    if want_assets:
        manual_or_owned_write(root, f"{specs_root_rel}/invariants/assets_rights_policy_invariants.yaml", asset_invariants(root, specs_root_rel, fuzz_root_rel), summary, "invariants")
        manual_or_owned_write(root, f"{specs_root_rel}/alloy/z00z_asset_rights_voucher.als", alloy_asset_model(), summary, "alloy")

    if want_crypto:
        manual_or_owned_write(root, f"{specs_root_rel}/invariants/crypto_invariants.yaml", crypto_invariants(root, specs_root_rel, fuzz_root_rel), summary, "invariants")
        manual_or_owned_write(root, f"{specs_root_rel}/crypto/domain_separation_registry.yaml", domain_registry(domains), summary, "crypto-spec")
        manual_or_owned_write(root, f"{specs_root_rel}/crypto/transcript_binding.md", transcript_binding(root), summary, "crypto-spec")
        manual_or_owned_write(root, f"{specs_root_rel}/crypto/proof_objects_schema.yaml", proof_objects_schema(root), summary, "crypto-spec")
        manual_or_owned_write(root, f"{specs_root_rel}/crypto/leakage_model.yaml", leakage_model(root), summary, "crypto-spec")
        manual_or_owned_write(root, f"{specs_root_rel}/tamarin/z00z_payment_request.spthy", tamarin_payment_request(), summary, "tamarin")
        manual_or_owned_write(root, f"{specs_root_rel}/tamarin/z00z_stealth_delivery.spthy", tamarin_stealth_delivery(), summary, "tamarin")
        manual_or_owned_write(root, f"{specs_root_rel}/tamarin/z00z_inbox_notify.spthy", tamarin_inbox_notify(), summary, "tamarin")
        manual_or_owned_write(root, f"{specs_root_rel}/tamarin/z00z_voucher_acceptance.spthy", tamarin_voucher_acceptance(), summary, "tamarin")
        manual_or_owned_write(root, f"{specs_root_rel}/proverif/z00z_payment_request_replay.pv", proverif_payment_request(), summary, "proverif")
        manual_or_owned_write(root, f"{specs_root_rel}/proverif/z00z_stealth_delivery.pv", proverif_stealth_delivery(), summary, "proverif")
        manual_or_owned_write(root, f"{specs_root_rel}/proverif/z00z_voucher_acceptance.pv", proverif_voucher_acceptance(), summary, "proverif")

    if want_security_review:
        manual_or_owned_write(root, f"{verification_root_rel}/security/prompt_corpus.json", security_prompt_corpus(root), summary, "security")
        manual_or_owned_write(root, f"{verification_root_rel}/security/attack_surface_registry.json", attack_surface_registry(root, scope_kind, target_root_rel, verification_root_rel), summary, "security")

    if want_exec:
        manual_or_owned_write(root, f"{verification_root_rel}/kani/targets.yaml", kani_targets(), summary, "verification")
        manual_or_owned_write(root, f"{verification_root_rel}/verus/targets.yaml", verus_targets(verification_root_rel), summary, "verification")
        manual_or_owned_write(root, f"{verification_root_rel}/verus/amount_arithmetic.rs", verus_amount_arithmetic(), summary, "verification")
        manual_or_owned_write(root, f"{verification_root_rel}/verus/rights_transfer.rs", verus_rights_transfer(), summary, "verification")
        manual_or_owned_write(root, f"{verification_root_rel}/verus/validator_determinism.rs", verus_validator_determinism(), summary, "verification")
        manual_or_owned_write(root, f"{verification_root_rel}/verus/transcript_domain.rs", verus_transcript_domain(), summary, "verification")
        manual_or_owned_write(root, f"{verification_root_rel}/model_coverage.yaml", model_coverage(root, specs_root_rel, verification_root_rel), summary, "verification")
        manual_or_owned_write(root, f"{verification_root_rel}/code-to-logic/targets.yaml", code_to_logic_targets(specs_root_rel, verification_root_rel), summary, "verification")
        manual_or_owned_write(root, code_to_logic_serial_id_manifest(verification_root_rel), code_to_logic_serial_id_cargo_toml(), summary, "verification")
        manual_or_owned_write(root, f"{code_to_logic_generated_root(verification_root_rel)}/serial_id_verify/src/lib.rs", code_to_logic_serial_id_lib(root, verification_root_rel), summary, "verification")
        manual_or_owned_write(root, f"{verification_root_rel}/code-to-logic/saw/serial_id_roundtrip.saw", code_to_logic_serial_id_saw(verification_root_rel), summary, "verification")
        manual_or_owned_write(root, code_to_logic_zkpack_manifest(verification_root_rel), code_to_logic_zkpack_cargo_toml(), summary, "verification")
        manual_or_owned_write(root, f"{code_to_logic_generated_root(verification_root_rel)}/zkpack_verify/build.rs", code_to_logic_zkpack_build_rs(), summary, "verification")
        manual_or_owned_write(root, f"{code_to_logic_generated_root(verification_root_rel)}/zkpack_verify/src/lib.rs", code_to_logic_zkpack_lib(root, verification_root_rel), summary, "verification")
        manual_or_owned_write(root, f"{specs_root_rel}/cryptol/serial_id.cry", cryptol_serial_id(), summary, "verification")
        manual_or_owned_write(root, f"{specs_root_rel}/cryptol/zkpack_wire.cry", cryptol_zkpack_wire(), summary, "verification")
        manual_or_owned_write(root, f"{verification_root_rel}/hax/Cargo.toml", hax_cargo_toml(root, verification_root_rel), summary, "verification")
        manual_or_owned_write(root, f"{verification_root_rel}/hax/src/lib.rs", hax_lib_rs(), summary, "verification")
        manual_or_owned_write(root, f"{verification_root_rel}/hax/targets.json", hax_targets_json(verification_root_rel), summary, "verification")
        manual_or_owned_write(root, f"{fuzz_root_rel}/Cargo.toml", fuzz_cargo_toml(root, fuzz_root_rel), summary, "fuzz")
        manual_or_owned_write(root, f"{fuzz_root_rel}/.gitignore", fuzz_gitignore(), summary, "fuzz")
        manual_or_owned_write(root, f"{fuzz_root_rel}/fuzz_targets/payment_request_compact.rs", fuzz_payment_request(), summary, "fuzz-target")
        manual_or_owned_write(root, f"{fuzz_root_rel}/fuzz_targets/receiver_card_record.rs", fuzz_receiver_card_record(), summary, "fuzz-target")
        manual_or_owned_write(root, f"{fuzz_root_rel}/fuzz_targets/checkpoint_artifact_bin.rs", fuzz_checkpoint_artifact_bin(), summary, "fuzz-target")
        manual_or_owned_write(root, f"{fuzz_root_rel}/fuzz_targets/asset_pkg_json.rs", fuzz_asset_pkg_json(), summary, "fuzz-target")
        if runtime_only:
            return summary
        kani_fixtures = extract_kani_fixture_payloads(root, verification_root_rel)
        manual_or_owned_write(root, "crates/z00z_core/fuzz/fuzz_targets/fuzz_target_asset_pack_from_bytes.rs", fuzz_core_asset_pack_from_bytes(), summary, "fuzz-target")
        manual_or_owned_write(root, "crates/z00z_crypto/fuzz/fuzz_targets/fuzz_from_bytes.rs", fuzz_crypto_from_bytes(), summary, "fuzz-target")
        manual_or_owned_write(root, "crates/z00z_crypto/fuzz/fuzz_targets/fuzz_take_32.rs", fuzz_crypto_take_32(), summary, "fuzz-target")
        manual_or_owned_write(root, "crates/z00z_wallets/tests/fixtures/generated_kani/compact.rs", kani_wallet_compact_fixtures(kani_fixtures), summary, "kani-fixture")
        manual_or_owned_write(root, "crates/z00z_storage/tests/fixtures/generated_kani/checkpoint.rs", kani_storage_checkpoint_fixtures(kani_fixtures), summary, "kani-fixture")
        manual_or_owned_write(root, "crates/z00z_core/tests/fixtures/generated_kani/asset_pkg.rs", kani_core_asset_pkg_fixtures(kani_fixtures), summary, "kani-fixture")
        manual_or_owned_write(root, "crates/z00z_wallets/tests/generated_kani_payment_request_compact.rs", kani_wallet_payment_request(), summary, "kani-harness")
        manual_or_owned_write(root, "crates/z00z_wallets/tests/generated_kani_receiver_card_record.rs", kani_wallet_receiver_card(), summary, "kani-harness")
        manual_or_owned_write(root, "crates/z00z_storage/tests/generated_kani_checkpoint_artifact.rs", kani_storage_checkpoint(), summary, "kani-harness")
        manual_or_owned_write(root, "crates/z00z_core/tests/generated_kani_asset_pkg_json.rs", kani_core_asset_pkg(), summary, "kani-harness")
        manual_or_owned_write(root, "crates/z00z_runtime/validators/tests/generated_kani_validator_checkpoint_flow.rs", kani_validator_checkpoint_flow(), summary, "kani-harness")

    return summary


def main() -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--root", required=True)
    parser.add_argument("--scope-kind", required=True, choices=["project", "crate"])
    parser.add_argument("--target-root-rel", default="")
    parser.add_argument("--summary-out")
    parser.add_argument("--specs-runtime-root")
    parser.add_argument("--verification-runtime-root")
    parser.add_argument("--fuzz-runtime-root")
    parser.add_argument("--runtime-only", action="store_true")
    args = parser.parse_args()

    root = Path(args.root).resolve()
    summary = build_artifacts(
        root,
        args.scope_kind,
        args.target_root_rel,
        args.specs_runtime_root,
        args.verification_runtime_root,
        args.fuzz_runtime_root,
        args.runtime_only,
    )

    if args.summary_out:
        out_path = Path(args.summary_out)
        out_path.parent.mkdir(parents=True, exist_ok=True)
        out_path.write_text(json.dumps(summary, indent=2, sort_keys=True), encoding="utf-8")
    else:
        print(json.dumps(summary, indent=2, sort_keys=True))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
